(235, 36, NULL, NULL, 'hallazgos', NULL, 'Safety tour al inicio de la intervención', NULL, '2026-03-02', 'pozos', '', 'aspecto_positivo', 'Realizó safety tour al inicio de la intervención en FRAP13, encontrando buenas condiciones de orden y aseo. Verifico el cierre de los hallazgos encontrados en la visita previa y recibe locación por parte de operaciones de superficie.', 'Ninguna', 'cerrada', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 'aprobado', NULL, NULL, NULL, '2026-03-05 00:00:00', '2026-03-05 00:00:00');
